CREATE TYPE "user_role" AS ENUM (
  'admin',
  'cashier',
  'client'
);

CREATE TYPE "payment_type" AS ENUM (
  'cash',
  'card',
  'transfer'
);

CREATE TYPE "stock_action" AS ENUM (
  'sale',
  'restock',
  'return'
);

CREATE TABLE "users" (
                         "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
                         "name" varchar,
                         "email" varchar UNIQUE,
                         "password_hash" varchar,
                         "role" user_role,
                         "created_at" timestamp,
                         "updated_at" timestamp
);

CREATE TABLE "categories" (
                              "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
                              "name" varchar,
                              "created_at" timestamp
);

CREATE TABLE "products" (
                            "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
                            "name" varchar,
                            "category_id" int,
                            "sku" varchar UNIQUE,
                            "price" decimal,
                            "stock" int,
                            "created_at" timestamp,
                            "updated_at" timestamp
);

CREATE TABLE "sales" (
                         "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
                         "cashier_id" int,
                         "client_id" int,
                         "total_amount" decimal,
                         "created_at" timestamp
);

CREATE TABLE "sale_items" (
                              "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
                              "sale_id" int,
                              "product_id" int,
                              "quantity" int,
                              "price" decimal
);

CREATE TABLE "payments" (
                            "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
                            "sale_id" int,
                            "amount" decimal,
                            "type" payment_type,
                            "created_at" timestamp
);

CREATE TABLE "stock_movements" (
                                   "id" INT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
                                   "product_id" int,
                                   "quantity" int,
                                   "action" stock_action,
                                   "created_at" timestamp
);

ALTER TABLE "products" ADD FOREIGN KEY ("category_id") REFERENCES "categories" ("id");

ALTER TABLE "sales" ADD FOREIGN KEY ("cashier_id") REFERENCES "users" ("id");

ALTER TABLE "sales" ADD FOREIGN KEY ("client_id") REFERENCES "users" ("id");

ALTER TABLE "sale_items" ADD FOREIGN KEY ("sale_id") REFERENCES "sales" ("id");

ALTER TABLE "sale_items" ADD FOREIGN KEY ("product_id") REFERENCES "products" ("id");

ALTER TABLE "payments" ADD FOREIGN KEY ("sale_id") REFERENCES "sales" ("id");

ALTER TABLE "stock_movements" ADD FOREIGN KEY ("product_id") REFERENCES "products" ("id");
